import { useEffect, useState } from "react";
import PropTypes from "prop-types";
import axios from "axios";
import { motion } from "framer-motion";
import {
  PieChart, Pie, Cell, LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid,
  BarChart, Bar, Legend, ResponsiveContainer
} from "recharts";
import { ChartBarIcon, CheckBadgeIcon } from "@heroicons/react/24/outline";

const StatCard = ({ title, value, icon: Icon, colorClass }) => (
  <motion.div
    whileHover={{ y: -5 }}
    className="glass p-6 rounded-3xl border border-white/10 shadow-[0_0_30px_rgba(0,0,0,0.3)] relative overflow-hidden group"
  >
    <div className={`absolute -right-6 -top-6 w-24 h-24 rounded-full blur-2xl opacity-20 transition-opacity group-hover:opacity-40 ${colorClass}`} />
    <div className="flex items-center justify-between mb-4 relative z-10">
      <h2 className="text-gray-400 text-sm font-semibold uppercase tracking-wider">{title}</h2>
      <div className={`p-2 rounded-xl bg-white/5 border border-white/10 ${colorClass.replace('bg-', 'text-')}`}>
        <Icon className="w-6 h-6" />
      </div>
    </div>
    <p className="text-4xl font-extrabold text-white relative z-10">{value}</p>
  </motion.div>
);

StatCard.propTypes = {
  title: PropTypes.string.isRequired,
  value: PropTypes.oneOfType([PropTypes.string, PropTypes.number]).isRequired,
  icon: PropTypes.elementType.isRequired,
  colorClass: PropTypes.string.isRequired,
};

const DepartmentAdminDashboard = () => {
  const user = JSON.parse(localStorage.getItem("user"));
  const department = user?.department;

  const [cards, setCards] = useState({ totalEvents: 0, registrations: 0 });
  const [monthlyRegistrations, setMonthlyRegistrations] = useState([]);
  const [deptEvents, setDeptEvents] = useState([]);
  const [loading, setLoading] = useState(true);

  const COLORS = ["#14b8a6", "#3b82f6"];
  const months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const [cardsRes, monthlyRes] = await Promise.all([
        axios.get(`http://localhost:5000/api/department-stats/cards/${department}`),
        axios.get(`http://localhost:5000/api/department-stats/monthly/${department}`),
      ]);
      setCards(cardsRes.data);
      setMonthlyRegistrations(
        monthlyRes.data.map(item => ({ month: months[item._id - 1], count: item.count }))
      );
      setDeptEvents([{ name: department, value: cardsRes.data.totalEvents }]);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-full">
        <div className="w-12 h-12 border-4 border-teal-500 border-t-transparent rounded-full animate-spin"></div>
      </div>
    );
  }

  return (
    <div className="pb-10">
      <div className="mb-10">
        <h1 className="text-4xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-teal-400 to-blue-500 mb-2">
          {department} Dashboard
        </h1>
        <p className="text-gray-400">Manage and track events exclusively for your department.</p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 mb-10">
        <StatCard title="Department Events" value={cards.totalEvents} icon={ChartBarIcon} colorClass="bg-teal-500 text-teal-400" />
        <StatCard title="Total Registrations" value={cards.registrations} icon={CheckBadgeIcon} colorClass="bg-blue-500 text-blue-400" />
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
        {/* Line Chart */}
        <div className="glass p-6 rounded-3xl border border-white/10 shadow-lg">
          <h3 className="text-xl font-bold text-white mb-6">Registration Trend</h3>
          <div className="w-full h-72">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={monthlyRegistrations}>
                <CartesianGrid strokeDasharray="3 3" stroke="#ffffff15" vertical={false} />
                <XAxis dataKey="month" stroke="#9ca3af" tick={{fill: '#9ca3af'}} axisLine={false} tickLine={false} />
                <YAxis stroke="#9ca3af" tick={{fill: '#9ca3af'}} axisLine={false} tickLine={false} />
                <Tooltip 
                  contentStyle={{ backgroundColor: 'rgba(0,0,0,0.8)', borderColor: 'rgba(255,255,255,0.1)', borderRadius: '12px', color: '#fff' }} 
                  itemStyle={{ color: '#fff' }}
                />
                <Line type="monotone" dataKey="count" stroke="#14b8a6" strokeWidth={4} dot={{fill: '#14b8a6', strokeWidth: 2, r: 4}} activeDot={{r: 6}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Pie Chart */}
        <div className="glass p-6 rounded-3xl border border-white/10 shadow-lg flex flex-col items-center">
          <h3 className="text-xl font-bold text-white mb-2 w-full text-left">Your Events Share</h3>
          <div className="w-full h-72">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={deptEvents} dataKey="value" cx="50%" cy="50%" innerRadius="0%" outerRadius="80%" paddingAngle={5} stroke="none">
                  {deptEvents.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                </Pie>
                <Tooltip contentStyle={{ backgroundColor: 'rgba(0,0,0,0.8)', borderColor: 'rgba(255,255,255,0.1)', borderRadius: '12px' }} />
                <Legend layout="horizontal" verticalAlign="bottom" align="center" wrapperStyle={{ paddingTop: '20px', color: '#9ca3af' }} />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Bar Chart */}
      <div className="glass p-6 rounded-3xl border border-white/10 shadow-lg">
        <h3 className="text-xl font-bold text-white mb-6">Monthly Growth Overview</h3>
        <div className="w-full h-80">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={monthlyRegistrations}>
              <CartesianGrid strokeDasharray="3 3" stroke="#ffffff15" vertical={false} />
              <XAxis dataKey="month" stroke="#9ca3af" tick={{fill: '#9ca3af'}} axisLine={false} tickLine={false} />
              <YAxis stroke="#9ca3af" tick={{fill: '#9ca3af'}} axisLine={false} tickLine={false} />
              <Tooltip 
                cursor={{fill: 'rgba(255,255,255,0.05)'}}
                contentStyle={{ backgroundColor: 'rgba(0,0,0,0.8)', borderColor: 'rgba(255,255,255,0.1)', borderRadius: '12px' }} 
              />
              <Bar dataKey="count" fill="#3b82f6" radius={[6, 6, 0, 0]} barSize={40} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default DepartmentAdminDashboard;

import { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";

const DepartmentEditEventDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [loading, setLoading] = useState(true);
  const [departments, setDepartments] = useState([]);
  const [events, setEvents] = useState([]);
  const [selectedDepartment, setSelectedDepartment] = useState("");
  const [selectedEvent, setSelectedEvent] = useState("");
  const [dynamicFields, setDynamicFields] = useState([]);

  // Load departments
  useEffect(() => {
    setDepartments(["SOE", "SOS", "SOM", "LAW", "PHARMACY"]);
  }, []);

  // Load event details
  useEffect(() => {
    const fetchDetails = async () => {
      try {
        const res = await fetch(
          `http://localhost:5000/api/event-details/detail/${id}`
        );
        const data = await res.json();

        const detail = Array.isArray(data) ? data[0] : data;
        if (detail) {
          setSelectedDepartment(detail.department);
          setSelectedEvent(detail.eventId?._id || detail.eventId);
          setDynamicFields(detail.dynamicFields || []);
        }
      } catch (err) {
        console.error("Fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchDetails();
  }, [id]);

  // Load events for selected department
  useEffect(() => {
    if (!selectedDepartment) return;

    fetch(`http://localhost:5000/api/events?department=${selectedDepartment}`)
      .then((res) => res.json())
      .then((data) => setEvents(data))
      .catch((err) => console.error(err));
  }, [selectedDepartment]);

  // Handle field changes
  const handleFieldChange = (index, key, value) => {
    const updated = [...dynamicFields];
    updated[index][key] = value;
    setDynamicFields(updated);
  };

  const handleAddField = () => {
    setDynamicFields([
      ...dynamicFields,
      { label: "", type: "text", options: [] },
    ]);
  };

  const handleDeleteField = (i) => {
    setDynamicFields(dynamicFields.filter((_, idx) => idx !== i));
  };

  // Save
  const handleSave = async () => {
    if (!selectedEvent || !selectedDepartment) {
      alert("Please select department and event");
      return;
    }

    try {
      const res = await fetch(
        `http://localhost:5000/api/event-details/${id}`,
        {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            eventId: selectedEvent,
            department: selectedDepartment,
            dynamicFields,
          }),
        }
      );

      const data = await res.json();

      if (res.ok) {
        alert("Event details updated successfully!");
        navigate("/department-admin/event-details-list");
      } else {
        alert(data.msg || "Update failed");
      }
    } catch (err) {
      console.error(err);
      alert("Server error");
    }
  };

  if (loading) return <p className="text-center mt-10">Loading...</p>;

  return (
    <div className="p-6 max-w-3xl mx-auto bg-white shadow-md rounded-xl mt-6">
      <h2 className="text-xl font-bold mb-4">Edit Event Details</h2>

      {/* Department */}
      <select
        value={selectedDepartment}
        disabled
        className="w-full border p-2 rounded mb-4 bg-gray-100 cursor-not-allowed"
      >
        <option value={selectedDepartment}>{selectedDepartment}</option>
      </select>

      {/* Event */}
      <select
        value={selectedEvent}
        disabled
        className="w-full border p-2 rounded mb-4 bg-gray-100 cursor-not-allowed"
      >
        {events.length > 0 && (
          <option value={selectedEvent}>
            {events.find((ev) => ev._id === selectedEvent)?.name ||
              "Selected Event"}
          </option>
        )}
      </select>

      {/* Dynamic Fields */}
      <h3 className="text-lg font-semibold mb-2">Edit Registration Fields</h3>

      {dynamicFields.map((field, i) => (
        <div
          key={i}
          className="mb-4 border p-3 rounded bg-gray-50 shadow-sm"
        >
          <input
            type="text"
            placeholder="Field Label"
            value={field.label}
            onChange={(e) =>
              handleFieldChange(i, "label", e.target.value)
            }
            className="border p-2 rounded mb-2 w-full"
          />

          <select
            value={field.type}
            onChange={(e) =>
              handleFieldChange(i, "type", e.target.value)
            }
            className="border p-2 rounded w-full"
          >
            <option value="text">Text</option>
            <option value="number">Number</option>
            <option value="email">Email</option>
            <option value="select">Select</option>
          </select>

          {field.type === "select" && (
            <input
              type="text"
              placeholder="Options comma separated"
              value={field.options?.join(",") || ""}
              onChange={(e) =>
                handleFieldChange(i, "options", e.target.value.split(","))
              }
              className="border p-2 rounded w-full mt-2"
            />
          )}

          {/* Delete button */}
          <button
            onClick={() => handleDeleteField(i)}
            className="bg-red-500 text-white px-3 py-1 rounded mt-2"
          >
            Delete
          </button>
        </div>
      ))}

      {/* Buttons */}
      <button
        onClick={handleAddField}
        className="bg-gray-400 text-white px-4 py-2 rounded mr-2"
      >
        Add Field
      </button>

      <button
        onClick={handleSave}
        className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
      >
        Save Changes
      </button>
    </div>
  );
};

export default DepartmentEditEventDetails;

import { useEffect, useState } from "react";
import { Link } from "react-router-dom";

const DepartmentEventDetailsList = () => {
  const [details, setDetails] = useState([]);

  // Get logged-in user
  const user = JSON.parse(localStorage.getItem("user"));
  const dept = user?.department || user?.dept || "";

  useEffect(() => {
    fetch("http://localhost:5000/api/event-details")
      .then((res) => res.json())
      .then((data) => {
        // If department admin → filter by their department
        if (user?.role === "department-admin") {
          const filtered = data.filter(
            (item) => item.department === dept
          );
          setDetails(filtered);
        } else {
          setDetails(data); // Super admin sees all
        }
      })
      .catch((err) => console.log(err));
  }, []);

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">
        {user?.role === "department-admin"
          ? `${dept} Department Event Details`
          : "Event Details"}
      </h2>

      <table className="w-full border">
        <thead>
          <tr className="bg-gray-200">
            <th className="p-2">Event Name</th>
            <th className="p-2">Department</th>
            <th className="p-2">Fields</th>
            <th className="p-2">Action</th>
          </tr>
        </thead>

        <tbody>
          {details.filter(d => d.eventId).map((d) => (
            <tr key={d._id} className="border-b">
              <td className="p-2">{d.eventId?.name}</td>
              <td className="p-2">{d.department}</td>
              <td className="p-2">{d.dynamicFields.length}</td>
              <td className="p-2">
                <Link
                  to={`/department-admin/event-details-edit/${d._id}`}
                  className="text-blue-600 underline"
                >
                  Edit
                </Link>
              </td>
            </tr>
          ))}
        </tbody>

      </table>
    </div>
  );
};

export default DepartmentEventDetailsList;

import { useEffect, useState } from "react";
import axios from "axios";
import { motion, AnimatePresence } from "framer-motion";
import { PencilIcon, TrashIcon, XMarkIcon } from "@heroicons/react/24/outline";

const DepartmentEventsList = () => {
  const [events, setEvents] = useState([]);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [loading, setLoading] = useState(true);

  const user = JSON.parse(localStorage.getItem("user"));
  const currentDept = user?.department || user?.dept || "";

  const fetchEvents = async () => {
    try {
      let url = "http://localhost:5000/api/events";
      if (user?.role === "department-admin" && currentDept) {
        url += `?department=${encodeURIComponent(currentDept)}`;
      }
      const res = await axios.get(url);
      setEvents(res.data);
    } catch (error) {
      console.error("Failed to load events:", error);
    } finally {
      setLoading(false);
    }
  };

  const deleteEvent = async (id) => {
    if (!window.confirm("Are you sure you want to delete this event? This action cannot be undone.")) return;
    try {
      await axios.delete(`http://localhost:5000/api/events/${id}`);
      setEvents((prev) => prev.filter((ev) => ev._id !== id));
    } catch (err) {
      console.error("Delete failed:", err);
    }
  };

  const updateEvent = async () => {
    try {
      await axios.put(`http://localhost:5000/api/events/${selectedEvent._id}`, {
        name: selectedEvent.name,
        description: selectedEvent.description,
        date: selectedEvent.date,
        departments: selectedEvent.departments,
        time: selectedEvent.time,
        location: selectedEvent.location,
        image: selectedEvent.image,
      });
      setSelectedEvent(null);
      fetchEvents();
    } catch (err) {
      console.error(err);
      alert("Failed to update event.");
    }
  };

  useEffect(() => {
    fetchEvents();
  }, []);

  return (
    <div className="pb-10 min-h-[80vh]">
      <div className="mb-8">
        <h1 className="text-3xl font-extrabold text-white mb-2">
          {user?.role === "department-admin" ? `${currentDept} Events` : "Manage Events"}
        </h1>
        <p className="text-gray-400">View, edit, and orchestrate all events under your jurisdiction.</p>
      </div>

      {loading ? (
        <div className="flex justify-center items-center h-40">
          <div className="w-10 h-10 border-4 border-teal-500 border-t-transparent rounded-full animate-spin"></div>
        </div>
      ) : (
        <div className="glass rounded-3xl border border-white/10 overflow-hidden shadow-[0_0_40px_rgba(0,0,0,0.3)]">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead className="bg-white/5 text-gray-400 text-sm uppercase tracking-wider border-b border-white/10">
                <tr>
                  <th className="px-6 py-4 font-semibold">Event Name</th>
                  <th className="px-6 py-4 font-semibold">Target Departments</th>
                  <th className="px-6 py-4 font-semibold">Date & Time</th>
                  <th className="px-6 py-4 font-semibold text-center">Registrations</th>
                  <th className="px-6 py-4 font-semibold text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/10">
                {events.length === 0 ? (
                  <tr>
                    <td colSpan="5" className="px-6 py-12 text-center text-gray-500 italic">No events found.</td>
                  </tr>
                ) : (
                  events.map((event) => (
                    <tr key={event._id} className="hover:bg-white/5 transition-colors group">
                      <td className="px-6 py-4">
                        <div className="font-bold text-white">{event.name}</div>
                        <div className="text-xs text-gray-500 truncate max-w-xs">{event.location}</div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex flex-wrap gap-1">
                          {(event.departments || []).map((dept, idx) => (
                            <span key={idx} className="px-2 py-0.5 text-xs font-semibold rounded bg-teal-500/20 text-teal-300 border border-teal-500/20">
                              {dept}
                            </span>
                          ))}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="text-white text-sm">{event.date}</div>
                        <div className="text-xs text-gray-500">{event.time}</div>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className="inline-block px-3 py-1 bg-green-500/20 text-green-400 rounded-full text-xs font-bold font-mono">
                          {event.totalRegistrations || 0}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button
                            onClick={() => setSelectedEvent(event)}
                            className="p-2 glass rounded-lg text-blue-400 hover:bg-blue-500/20 hover:text-blue-300 transition"
                            title="Edit Event"
                          >
                            <PencilIcon className="w-5 h-5" />
                          </button>
                          <button
                            onClick={() => deleteEvent(event._id)}
                            className="p-2 glass rounded-lg text-red-400 hover:bg-red-500/20 hover:text-red-300 transition"
                            title="Delete Event"
                          >
                            <TrashIcon className="w-5 h-5" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Edit Modal */}
      <AnimatePresence>
        {selectedEvent && (
          <motion.div
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/80 backdrop-blur-md flex items-center justify-center z-[100] p-4"
          >
            <motion.div
              initial={{ scale: 0.95, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.95, y: 20 }}
              className="bg-black border border-white/10 rounded-3xl shadow-[0_0_50px_rgba(0,0,0,0.8)] w-full max-w-2xl relative overflow-hidden"
            >
              <div className="absolute top-0 right-0 w-64 h-64 bg-teal-600/10 rounded-full blur-[80px] pointer-events-none" />
              
              <div className="p-6 border-b border-white/10 flex justify-between items-center relative z-10">
                <h2 className="text-2xl font-bold text-white">Edit Event</h2>
                <button
                  onClick={() => setSelectedEvent(null)}
                  className="p-2 text-gray-400 hover:text-white bg-white/5 hover:bg-white/10 rounded-full transition"
                >
                  <XMarkIcon className="w-5 h-5" />
                </button>
              </div>

              <div className="p-6 space-y-5 overflow-y-auto max-h-[70vh] relative z-10 webkit-scrollbar-hide">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                  <div className="md:col-span-2">
                    <label className="block text-gray-400 text-sm font-medium mb-1">Event Name</label>
                    <input
                      className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-teal-500 transition outline-none"
                      value={selectedEvent.name}
                      onChange={(e) => setSelectedEvent({ ...selectedEvent, name: e.target.value })}
                    />
                  </div>

                  <div className="md:col-span-2">
                    <label className="block text-gray-400 text-sm font-medium mb-1">Description</label>
                    <textarea
                      rows={2}
                      className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-teal-500 transition outline-none resize-none"
                      value={selectedEvent.description}
                      onChange={(e) => setSelectedEvent({ ...selectedEvent, description: e.target.value })}
                    />
                  </div>

                  <div>
                    <label className="block text-gray-400 text-sm font-medium mb-1">Date</label>
                    <input
                      type="date"
                      className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-teal-500 transition outline-none [color-scheme:dark]"
                      value={selectedEvent.date}
                      onChange={(e) => setSelectedEvent({ ...selectedEvent, date: e.target.value })}
                    />
                  </div>

                  <div>
                    <label className="block text-gray-400 text-sm font-medium mb-1">Time</label>
                    <input
                      type="time"
                      className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-teal-500 transition outline-none [color-scheme:dark]"
                      value={selectedEvent.time}
                      onChange={(e) => setSelectedEvent({ ...selectedEvent, time: e.target.value })}
                    />
                  </div>

                  <div className="md:col-span-2">
                    <label className="block text-gray-400 text-sm font-medium mb-1">Location</label>
                    <input
                      className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-teal-500 transition outline-none"
                      value={selectedEvent.location}
                      onChange={(e) => setSelectedEvent({ ...selectedEvent, location: e.target.value })}
                    />
                  </div>

                  <div className="md:col-span-2">
                    <label className="block text-gray-400 text-sm font-medium mb-1">Image URL</label>
                    <input
                      className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-teal-500 transition outline-none"
                      value={selectedEvent.image}
                      onChange={(e) => setSelectedEvent({ ...selectedEvent, image: e.target.value })}
                    />
                  </div>

                  <div className="md:col-span-2">
                    <label className="block text-gray-400 text-sm font-medium mb-1">Target Departments</label>
                    <input
                      className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-gray-500 cursor-not-allowed outline-none"
